import logging
import json
from datetime import datetime
from flask import request, g
import os

class WebAppLogger:
    def __init__(self, log_file='app.log', log_level=logging.INFO):
        self.logger = logging.getLogger('webapp')
        self.logger.setLevel(log_level)
        
        if not self.logger.handlers:
            file_handler = logging.FileHandler(log_file)
            file_handler.setLevel(log_level)
            
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
            )
            file_handler.setFormatter(formatter)
            self.logger.addHandler(file_handler)
    
    def log_request(self, level=logging.INFO, **kwargs):
        log_data = {
            'timestamp': datetime.utcnow().isoformat(),
            'method': request.method,
            'url': request.url,
            'remote_addr': request.remote_addr,
            'user_agent': request.headers.get('User-Agent'),
            'request_id': getattr(g, 'request_id', None)
        }
        
        log_data.update(kwargs)
        
        message = json.dumps(log_data, separators=(',', ':'))
        self.logger.log(level, message)
    
    def info(self, message, **kwargs):
        self.log_request(logging.INFO, message=message, **kwargs)
    
    def error(self, message, **kwargs):
        self.log_request(logging.ERROR, message=message, **kwargs)
    
    def warning(self, message, **kwargs):
        self.log_request(logging.WARNING, message=message, **kwargs)
    
    def debug(self, message, **kwargs):
        self.log_request(logging.DEBUG, message=message, **kwargs)

# Global logger instance
web_logger = WebAppLogger()

# Example usage in Flask app
def log_request_info():
    web_logger.info("Request processed successfully")

def log_request_error(error):
    web_logger.error(f"Request failed with error: {error}")